assignments.value:
={{(() => {
  const data = $input.item.json;

  let raw =
    data.output?.agent_output ??
    data.agent_output ??
    data.output2?.text ??
    data.text ??
    data.message ??
    data.response ??
    data.result ??
    '';

  if (typeof raw === 'object' && !Array.isArray(raw)) {
    raw = Object.values(raw).join(' ');
  }

  if (Array.isArray(raw)) {
    raw = raw.map(item => {
      if (typeof item === 'string') return item;
      if (typeof item === 'object') return Object.values(item).join(' ');
      return String(item);
    }).join(' ');
  }

  let text = String(raw);

  const tokens = { time: [] };

  text = text.replace(/\b\d{2}:\d{2}\b/g, (match) => {
    const id = `__TIME_${tokens.time.length}__`;
    tokens.time.push(match);
    return id;
  });

  text = text
    .replace(/\r/g, '')
    .replace(/\n\s+/g, '\n')
    .replace(/[ \t]{2,}/g, ' ');

  // 🔥 remove quebra automática após ":" (causa do bug)
  text = text
    .replace(/([!?])\s+(?=[A-ZÁÉÍÓÚÂÊÎÔÛÃÕ])/g, '$1\n\n')
    .replace(/(?<!\d)\.\s+(?=[A-ZÁÉÍÓÚÂÊÎÔÛÃÕ])/g, '.\n\n');

  // 🔥 bloco de horários: garante só 1 quebra antes
  text = text.replace(
    /((?:__TIME_\d+__\s*,?\s*){2,})/g,
    '\n$1\n'
  );

  text = text
    .replace(/\n\.\n/g, '.\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/\n\s+\n/g, '\n\n') // remove linhas "vazias com espaço"
    .trim();

  tokens.time.forEach((value, i) => {
    text = text.replace(`__TIME_${i}__`, value);
  });

  return text;
})()}}

={{ 
  ($('get memories 1').item.json.memories || [])
    .map(memory => {
      const parsed = JSON.parse(memory);

      let content = parsed?.data?.content || '';

      if (parsed.type === 'ai') {
        try {
          const aiContent = JSON.parse(content);

          content =
            aiContent?.output?.agent_output ||
            aiContent?.agent_output ||
            aiContent?.output ||
            content;

          if (Array.isArray(content)) {
            content = content.join('\n');
          }

          if (typeof content === 'object') {
            content = JSON.stringify(content);
          }
        } catch (e) {}
      }

      return {
        type: parsed.type,
        content: String(content || '').trim()
      };
    })
    .filter(memory => ['ai', 'human'].includes(memory.type))
    .filter(memory => memory.content)
    .slice(0, 3)
    .reverse()
    .map(memory => `${memory.type}: ${memory.content}`)
    .join('\n')
}}

